module counter_4bit (reset_clk, rst, en, count);
   input reset_clk, rst, en;
   output [3:0] count;

   reg [3:0] count;

always @(posedge reset_clk or posedge rst) begin
    if (rst) 
    begin
        count <= 0;
    end 
    else if (en) 
    begin
        count <= count + 1;
    end
end

endmodule
